"use client"

import { useState, useEffect } from "react"
import { Button } from "@/components/ui/button"
import { Input } from "@/components/ui/input"
import { Badge } from "@/components/ui/badge"
import { api } from "@/lib/api"
import type { Task, TaskStatus, TaskPriority, Comment, FileAttachment } from "@/types"
import { X, Send, Paperclip, Trash2, Download, Sparkles } from "lucide-react"
import { format } from "date-fns"
import { cn } from "@/lib/utils"

interface TaskModalProps {
  task: Task | null
  projectId: string
  onClose: () => void
  onUpdate: (task: Task) => void
  onDelete: (taskId: string) => void
}

const statuses: TaskStatus[] = ["backlog", "todo", "in_progress", "review", "done"]
const priorities: TaskPriority[] = ["low", "medium", "high", "critical"]

export function TaskModal({ task, projectId, onClose, onUpdate, onDelete }: TaskModalProps) {
  const [editedTask, setEditedTask] = useState<Partial<Task>>({})
  const [comments, setComments] = useState<Comment[]>([])
  const [attachments, setAttachments] = useState<FileAttachment[]>([])
  const [newComment, setNewComment] = useState("")
  const [suggestions, setSuggestions] = useState<any>(null)
  const [loading, setLoading] = useState(false)

  useEffect(() => {
    if (task) {
      setEditedTask(task)
      loadComments()
      loadAttachments()
    }
  }, [task])

  const loadComments = async () => {
    if (!task) return
    try {
      const { comments } = await api.getComments(task._id)
      setComments(comments)
    } catch (error) {
      console.error("Failed to load comments:", error)
    }
  }

  const loadAttachments = async () => {
    if (!task) return
    try {
      const { attachments } = await api.getAttachments(task._id)
      setAttachments(attachments)
    } catch (error) {
      console.error("Failed to load attachments:", error)
    }
  }

  const handleSave = async () => {
    if (!task) return
    setLoading(true)
    try {
      const { task: updated } = await api.updateTask(task._id, {
        title: editedTask.title,
        description: editedTask.description,
        status: editedTask.status,
        priority: editedTask.priority,
        due_date: editedTask.due_date,
        time_estimate_hours: editedTask.time_estimate_hours,
        version: task.version,
      })
      onUpdate(updated)
    } catch (error: any) {
      if (error.message.includes("conflict")) {
        alert("This task was modified by another user. Please refresh and try again.")
      }
    } finally {
      setLoading(false)
    }
  }

  const handleAddComment = async () => {
    if (!task || !newComment.trim()) return
    try {
      const { comment } = await api.createComment(task._id, newComment)
      setComments([...comments, comment])
      setNewComment("")
    } catch (error) {
      console.error("Failed to add comment:", error)
    }
  }

  const handleFileUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    if (!task || !e.target.files?.length) return
    const file = e.target.files[0]
    try {
      const { attachment } = await api.uploadAttachment(task._id, file)
      setAttachments([...attachments, attachment])
    } catch (error) {
      console.error("Failed to upload file:", error)
    }
  }

  const handleDeleteAttachment = async (attachmentId: string) => {
    try {
      await api.deleteAttachment(attachmentId)
      setAttachments(attachments.filter((a) => a._id !== attachmentId))
    } catch (error) {
      console.error("Failed to delete attachment:", error)
    }
  }

  const handleGetSuggestions = async () => {
    if (!editedTask.title) return
    try {
      const { suggestions } = await api.getSuggestions(
        editedTask.title || "",
        editedTask.description || "",
        projectId
      )
      setSuggestions(suggestions)
    } catch (error) {
      console.error("Failed to get suggestions:", error)
    }
  }

  const handleDelete = async () => {
    if (!task || !confirm("Are you sure you want to delete this task?")) return
    try {
      await api.deleteTask(task._id)
      onDelete(task._id)
      onClose()
    } catch (error) {
      console.error("Failed to delete task:", error)
    }
  }

  if (!task) return null

  return (
    <div className="fixed inset-0 bg-black/50 flex items-center justify-center z-50">
      <div className="bg-white rounded-lg w-full max-w-3xl max-h-[90vh] overflow-hidden flex flex-col">
        <div className="flex items-center justify-between p-4 border-b">
          <h2 className="text-lg font-semibold">Task Details</h2>
          <Button variant="ghost" size="icon" onClick={onClose}>
            <X className="h-4 w-4" />
          </Button>
        </div>

        <div className="flex-1 overflow-y-auto p-4 space-y-4">
          <div>
            <label className="text-sm font-medium">Title</label>
            <Input
              value={editedTask.title || ""}
              onChange={(e) => setEditedTask({ ...editedTask, title: e.target.value })}
              className="mt-1"
            />
          </div>

          <div>
            <label className="text-sm font-medium">Description</label>
            <textarea
              value={editedTask.description || ""}
              onChange={(e) => setEditedTask({ ...editedTask, description: e.target.value })}
              className="mt-1 w-full h-24 px-3 py-2 border rounded-md text-sm"
            />
          </div>

          <div className="grid grid-cols-2 gap-4">
            <div>
              <label className="text-sm font-medium">Status</label>
              <select
                value={editedTask.status || "backlog"}
                onChange={(e) => setEditedTask({ ...editedTask, status: e.target.value as TaskStatus })}
                className="mt-1 w-full h-9 px-3 border rounded-md text-sm"
              >
                {statuses.map((s) => (
                  <option key={s} value={s}>{s.replace("_", " ")}</option>
                ))}
              </select>
            </div>
            <div>
              <label className="text-sm font-medium">Priority</label>
              <select
                value={editedTask.priority || "medium"}
                onChange={(e) => setEditedTask({ ...editedTask, priority: e.target.value as TaskPriority })}
                className="mt-1 w-full h-9 px-3 border rounded-md text-sm"
              >
                {priorities.map((p) => (
                  <option key={p} value={p}>{p}</option>
                ))}
              </select>
            </div>
          </div>

          <div className="grid grid-cols-2 gap-4">
            <div>
              <label className="text-sm font-medium">Due Date</label>
              <Input
                type="date"
                value={editedTask.due_date?.split("T")[0] || ""}
                onChange={(e) => setEditedTask({ ...editedTask, due_date: e.target.value })}
                className="mt-1"
              />
            </div>
            <div>
              <label className="text-sm font-medium">Time Estimate (hours)</label>
              <Input
                type="number"
                value={editedTask.time_estimate_hours || ""}
                onChange={(e) => setEditedTask({ ...editedTask, time_estimate_hours: Number(e.target.value) })}
                className="mt-1"
              />
            </div>
          </div>

          <div className="flex gap-2">
            <Button variant="outline" size="sm" onClick={handleGetSuggestions}>
              <Sparkles className="h-4 w-4 mr-1" /> AI Suggestions
            </Button>
          </div>

          {suggestions && (
            <div className="p-3 bg-blue-50 rounded-lg text-sm space-y-2">
              <p><strong>Suggested Priority:</strong> {suggestions.suggested_priority}</p>
              {suggestions.next_steps?.length > 0 && (
                <div>
                  <strong>Next Steps:</strong>
                  <ul className="list-disc list-inside">
                    {suggestions.next_steps.map((step: string, i: number) => (
                      <li key={i}>{step}</li>
                    ))}
                  </ul>
                </div>
              )}
            </div>
          )}

          <div>
            <label className="text-sm font-medium">Attachments</label>
            <div className="mt-2 space-y-2">
              {attachments.map((att) => (
                <div key={att._id} className="flex items-center justify-between p-2 bg-gray-50 rounded">
                  <span className="text-sm">{att.original_name}</span>
                  <div className="flex gap-1">
                    <a 
                      href={`http://localhost:5000/api${att.download_url}`} 
                      target="_blank"
                      className="inline-flex items-center justify-center h-6 w-6 rounded-md hover:bg-gray-100 transition-colors"
                    >
                      <Download className="h-3 w-3" />
                    </a>
                    <Button variant="ghost" size="icon" className="h-6 w-6" onClick={() => handleDeleteAttachment(att._id)}>
                      <Trash2 className="h-3 w-3" />
                    </Button>
                  </div>
                </div>
              ))}
              <label className="flex items-center gap-2 cursor-pointer text-sm text-blue-600">
                <Paperclip className="h-4 w-4" />
                Add attachment
                <input type="file" className="hidden" onChange={handleFileUpload} />
              </label>
            </div>
          </div>

          <div>
            <label className="text-sm font-medium">Comments</label>
            <div className="mt-2 space-y-3">
              {comments.map((comment) => (
                <div key={comment._id} className="p-3 bg-gray-50 rounded-lg">
                  <div className="flex items-center gap-2 mb-1">
                    <span className="font-medium text-sm">{comment.author?.name}</span>
                    <span className="text-xs text-gray-500">
                      {format(new Date(comment.created_at), "MMM d, h:mm a")}
                    </span>
                  </div>
                  <p className="text-sm">{comment.content}</p>
                </div>
              ))}
              <div className="flex gap-2">
                <Input
                  value={newComment}
                  onChange={(e) => setNewComment(e.target.value)}
                  placeholder="Add a comment..."
                  onKeyDown={(e) => e.key === "Enter" && handleAddComment()}
                />
                <Button size="icon" onClick={handleAddComment}>
                  <Send className="h-4 w-4" />
                </Button>
              </div>
            </div>
          </div>
        </div>

        <div className="flex items-center justify-between p-4 border-t">
          <Button variant="destructive" onClick={handleDelete}>
            <Trash2 className="h-4 w-4 mr-1" /> Delete
          </Button>
          <div className="flex gap-2">
            <Button variant="outline" onClick={onClose}>Cancel</Button>
            <Button onClick={handleSave} disabled={loading}>
              {loading ? "Saving..." : "Save Changes"}
            </Button>
          </div>
        </div>
      </div>
    </div>
  )
}
